#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

struct Node{
    int son[2],rs;
}t[N*32];

int n,q,v[N],root[N],tot;
int f[N],sz[N],dep[N],son[N],top[N],dfn[N],w[N],num;
vector<int> e[N];

void dfs1(int x,int fa){
    f[x]=fa,sz[x]=1,dep[x]=dep[fa]+1;
    for(int y:e[x])
        if(y!=fa){
            dfs1(y,x);
            if(sz[y]>sz[son[x]])
                son[x]=y;
            sz[x]+=sz[y];
        }
}

void dfs2(int x,int fa,int topx){
    top[x]=topx;
    dfn[x]=++num,w[num]=x;
    if(son[x])
        dfs2(son[x],x,topx);
    for(int y:e[x])
        if(y!=fa && y!=son[x])
            dfs2(y,x,y);
}

void Add(int p,int q,int val,int x){
    for(int i=29;i>=0;i--){
        t[p].son[0]=t[q].son[0];
        t[p].son[1]=t[q].son[1];
        p=t[p].son[(val>>i)&1]=++tot;
        q=t[q].son[(val>>i)&1];
        t[p].rs=x;
    }
}

int query(int l,int r,int val){
    int res=0,p=root[r];
    for(int i=29;i>=0;i--){
        int num=((val>>i)&1);
        if(t[t[p].son[num^1]].rs>=l)
            res|=(1<<i),p=t[p].son[num^1];
        else
            p=t[p].son[num];
    }
    return res;
}

int Ask(int x,int y,int val){
    int res=0;
    while(top[x]!=top[y]){
        if(dep[top[x]]<dep[top[y]])
            swap(x,y);
        res=max(res,query(dfn[top[x]],dfn[x],val)),x=f[top[x]];
    }
    if(dep[x]<dep[y])
        return max(res,query(dfn[x],dfn[y],val));
    else
        return max(res,query(dfn[y],dfn[x],val));
}

int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        scanf("%d",&v[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    dfs1(1,0);
    dfs2(1,0,1);
    for(int i=1;i<=n;i++){
        root[i]=++tot;
        Add(root[i],root[i-1],v[w[i]],i);
    }
    while(q--){
        int op,x,y,z;
        scanf("%d",&op);
        if(op==1){
            scanf("%d%d",&x,&z);
            printf("%d\n",query(dfn[x],dfn[x]+sz[x]-1,z));
        }else{
            scanf("%d%d%d",&x,&y,&z);
            printf("%d\n",Ask(x,y,z));
        }
    }
    return 0;
}
